// Funci�n para preservar UTF-8 correctamente
function fixUtf8(str) {
  if (!str) return '';
  try {
    // Si ya es UTF-8 v�lido, devolverlo tal cual
    return decodeURIComponent(encodeURIComponent(str));
  } catch (e) {
    // Limpiar caracteres inv�lidos
    return str.replace(/[\uFFFD\uFFFE\uFFFF]/g, '').replace(/\x00/g, '');
  }
}

const body = $input.first().json.body || $input.first().json;
const companySlug = body.company_slug || 'default';
const assistantName = fixUtf8(body.assistant_name) || 'MIA';
const companyName = fixUtf8(body.company_name) || 'la empresa';
