    text_to_save: textToSave
  }
};

const processData = $('Process Response').first().json;

// Check if we should skip saving
if (processData.should_save === false) {
  return { json: { skip_save: true, ai_response: processData.ai_response } };
}

const embedding = $input.first().json.data[0].embedding;
const timestamp = new Date().toISOString();
const dedup = processData.deduplication || {};
const action = dedup.action || 'create';

// Qdrant requires integer or UUID point IDs - ensure numeric
let pointId = dedup.point_id || Date.now();
if (typeof pointId === 'string') {
  const uuidRe = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
  if (uuidRe.test(pointId)) {
    // valid UUID, keep as is
  } else if (/^\d+$/.test(pointId)) {
    pointId = parseInt(pointId, 10);
  } else {
    // Not UUID, not numeric string - generate numeric ID
    pointId = Date.now() * 10 + Math.floor(Math.random() * 10);
  }
}

const userMsg = processData.user_message || '';
const knowledgeText = userMsg.trim();

return {
  json: {
    skip_save: false,
    collection_name: processData.collection_name,
    qdrant_host: processData.qdrant_host,
    qdrant_api_key: processData.qdrant_api_key || '',
    ai_response: processData.ai_response,
    action: action,
    point: {
      id: pointId,
      vector: embedding,
      payload: {
        text: knowledgeText,
        content: knowledgeText,
        type: 'training_message',
        category: 'entrenamiento',
        company_slug: processData.company_slug,
        action: action,
        similarity: dedup.similarity || 0,
        last_updated: timestamp
      }
    }
  }
};

const data = $input.first().json;

// If skip_save is true, just pass through
if (data.skip_save === true) {
  return {
    json: {
      skipped: true,
      ai_response: data.ai_response
    }
  };
}

// Make the Qdrant request
const qdrantHost = data.qdrant_host;
const collectionName = data.collection_name;
const point = data.point;

const response = await this.helpers.httpRequest({
  method: 'PUT',
  url: `${qdrantHost}/collections/${collectionName}/points`,
  headers: {
    'Content-Type': 'application/json; charset=utf-8',
    'api-key': data.qdrant_api_key || ''
  },
  body: {
    points: [{
      id: point.id,
      vector: point.vector,
      payload: point.payload
    }]
  },
  json: true
});

return {
  json: {
    skipped: false,
    stored: true,
    ai_response: data.ai_response,
    qdrant_response: response
  }
};

const data = $input.first().json;
return {
  json: {
    response: data.ai_response,
    saved: !data.skipped,
    message: data.skipped ? 'Respuesta sin guardar' : 'Guardado en la base de conocimiento'
  }
};

// Return response (not saved path)
